  2	 * Add Source Modal Component
  3	 *
  4	 * This component displays a modal for adding or editing a source of a specific type. It provides
  5	 * a form to input source details including name, hosts, port, credential, proxy URL and SSL settings.
  6	 *
  7	 * @module addSourceModal
  8	 */
  9	import React, { useCallback, useEffect, useState } from 'react';
 10	import {
 11	  ActionGroup,
 12	  Button,
 13	  Checkbox,
 14	  Form,
 15	  FormGroup,
 16	  HelperText,
 17	  HelperTextItem,
 18	  Modal,
 19	  ModalVariant,
 20	  TextArea,
 21	  TextInput
 22	} from '@patternfly/react-core';
 23	import { SimpleDropdown } from '../../components/simpleDropdown/simpleDropdown';
 24	import { TypeaheadCheckboxes } from '../../components/typeAheadCheckboxes/typeaheadCheckboxes';
 25	import { helpers } from '../../helpers';
 26	import { useGetCredentialsApi } from '../../hooks/useCredentialApi';
 27	import { type SourceType } from '../../types/types';
 28	
 29	const SSL_PROTOCOL_LABELS_TO_VALUES: Record<string, string> = {
 30	  SSLv23: 'SSLv23',
 31	  TLSv1: 'TLSv1',
 32	  'TLSv1.1': 'TLSv1_1',
 33	  'TLSv1.2': 'TLSv1_2',
 34	  'Disable SSL': 'disable'
 35	};
 36	
 37	const SSL_PROTOCOL_VALUES_TO_LABELS: Record<string, string> = {
 38	  SSLv23: 'SSLv23',
 39	  TLSv1: 'TLSv1',
 40	  TLSv1_1: 'TLSv1.1',
 41	  TLSv1_2: 'TLSv1.2',
 42	  disable: 'Disable SSL'
 43	};
 44	
 45	interface AddSourceModalProps {
 46	  isOpen: boolean;
 47	  source?: SourceType;
 48	  sourceType?: string;
 49	  onClose?: () => void;
 50	  onSubmit?: (payload: any) => void;
 51	}
 52	
 53	interface SourceFormProps extends Omit<AddSourceModalProps, 'isOpen'> {
 54	  useForm?: typeof useSourceForm;
 55	}
 56	
 57	interface SourceFormType {
 58	  credentials?: number[];
 59	  useParamiko?: boolean;
 60	  sslVerify?: boolean;
 61	  sslProtocol: string;
 62	  name?: string;
 63	  hosts?: string;
 64	  port?: string;
 65	  proxy_url?: string;
 66	}
 67	
 68	const useSourceForm = ({
 69	  sourceType,
 70	  source,
 71	  useGetCredentials = useGetCredentialsApi
 72	}: { sourceType?: string; source?: Partial<SourceType>; useGetCredentials?: typeof useGetCredentialsApi } = {}) => {
 73	  const initialFormState: SourceFormType = {
 74	    credentials: [],
 75	    useParamiko: false,
 76	    sslVerify: true,
 77	    sslProtocol: 'SSLv23',
 78	    name: '',
 79	    hosts: '',
 80	    port: '',
 81	    proxy_url: ''
 82	  };
 83	
 84	  const { getCredentials } = useGetCredentials();
 85	  const [credOptions, setCredOptions] = useState<{ value: string; label: string }[] | []>([]);
 86	  const [formData, setFormData] = useState<SourceFormType>(initialFormState);
 87	
 88	  const typeValue = source?.source_type || sourceType?.split(' ')?.shift()?.toLowerCase();
 89	  const isNetwork = typeValue === 'network';
 90	  const isOpenshift = typeValue === 'openshift';
 91	
 92	  const getCleanedSourceData = (formData: Record<string, any>) => {
 93	    const cleanedData = { ...formData };
 94	
 95	    Object.entries(cleanedData).forEach(([key, value]) => {
 96	      if (value === '') {
 97	        delete cleanedData[key];
 98	      }
 99	    });
100	
101	    return cleanedData;
102	  };
103	
104	  // Edit props, reset state on unmount
105	  useEffect(() => {
106	    if (source) {
107	      setFormData({
108	        credentials: source?.credentials?.map(c => c.id) || [],
109	        useParamiko: source?.use_paramiko || false,
110	        sslVerify: source?.ssl_cert_verify ?? true,
111	        sslProtocol: source?.disable_ssl
112	          ? 'Disable SSL'
113	          : SSL_PROTOCOL_VALUES_TO_LABELS[source?.ssl_protocol || 'SSLv23'],
114	        name: source?.name || '',
115	        hosts: source?.hosts?.join(',') || '',
116	        port: source?.port?.toString() || '',
117	        proxy_url: source?.proxy_url || ''
118	      });
119	    }
120	
121	    return () => {
122	      setFormData(initialFormState);
123	    };
124	    // eslint-disable-next-line react-hooks/exhaustive-deps
125	  }, []);
126	
127	  useEffect(() => {
128	    getCredentials({
129	      params: {
130	        cred_type: typeValue
131	      }
132	    })
133	      .then(response => {
134	        const updatedOptions = response?.data?.results?.map(({ name, id }) => ({ label: name, value: `${id}` }));
135	        setCredOptions(updatedOptions || []);
136	      })
137	      .catch(err => {
138	        if (!helpers.TEST_MODE) {
139	          console.error(err);
140	        }
141	      });
142	  }, [typeValue, getCredentials]);
143	
144	  const handleInputChange = useCallback(
145	    (field: string, value: unknown) => {
146	      setFormData({ ...formData, [field]: value });
147	    },
148	    [formData]
149	  );
150	
151	  const filterFormData = useCallback(
152	    (data = formData) => {
153	      const { credentials, useParamiko, sslVerify, sslProtocol, name, hosts, port, proxy_url } = data;
154	      const payload: any = {
155	        name,
156	        credentials: credentials?.map(c => Number(c)),
157	        hosts: helpers.normalizeCommaSeparated(hosts),
158	        port: port || (isOpenshift && '6443') || (isNetwork && '22') || '443',
159	        ...(!source && { source_type: typeValue }),
160	        ...(source && { id: source.id })
161	      };
162	
163	      if (!isNetwork) {
164	        const apiValue = SSL_PROTOCOL_LABELS_TO_VALUES[sslProtocol];
165	        if (apiValue !== 'disable') {
166	          payload.ssl_protocol = apiValue;
167	          payload.ssl_cert_verify = sslVerify;
168	          payload.disable_ssl = false;
169	        } else {
170	          payload.disable_ssl = true;
171	        }
172	        if (proxy_url) {
173	          payload.proxy_url = proxy_url;
174	        }
175	      } else {
176	        payload.use_paramiko = useParamiko;
177	      }
178	
179	      return getCleanedSourceData(payload);
180	    },
181	    [isNetwork, isOpenshift, formData, source, typeValue, getCleanedSourceData]
182	  );
183	
184	  return {
185	    credOptions,
186	    formData,
187	    isNetwork,
188	    isOpenshift,
189	    handleInputChange,
190	    filterFormData,
191	    typeValue
192	  };
193	};
194	
195	const SourceForm: React.FC<SourceFormProps> = ({
196	  source,
197	  sourceType,
198	  onClose = () => {},
199	  onSubmit = () => {},
200	  useForm = useSourceForm
201	}) => {
202	  const { formData, isNetwork, isOpenshift, credOptions, handleInputChange, filterFormData } = useForm({
203	    sourceType,
204	    source
205	  });
206	  const onAdd = () => onSubmit(filterFormData());
207	
208	  return (
209	    <Form>
210	      <FormGroup label="Name" isRequired fieldId="name">
211	        <TextInput
212	          value={formData?.name}
213	          placeholder="Enter a name for the source"
214	          isRequired
215	          type="text"
216	          id="source-name"
217	          name="name"
218	          onChange={event => handleInputChange('name', (event.target as HTMLInputElement).value)}
219	          ouiaId="name"
220	        />
221	      </FormGroup>
222	      <FormGroup label="Credentials" fieldId="credentials" isRequired>
223	        <TypeaheadCheckboxes
224	          onChange={(selections: string[]) => {
225	            const validIds = selections.map(Number).filter(id => !isNaN(id));
226	            handleInputChange('credentials', validIds);
227	          }}
228	          options={credOptions}
229	          selectedOptions={formData?.credentials?.map(String) || []}
230	          menuToggleOuiaId="add_credentials_select"
231	          maxSelections={isNetwork ? Infinity : 1} // Limit selection to 1 for non-network sources
232	        />
233	        {!isNetwork && (
234	          <HelperText>
235	            <HelperTextItem variant="warning">Only one credential can be selected for this source type.</HelperTextItem>
236	          </HelperText>
237	        )}
238	      </FormGroup>
239	      {isNetwork ? (
240	        <React.Fragment>
241	          <FormGroup label="Search addresses" isRequired fieldId="hosts">
242	            <TextArea
243	              placeholder="Enter values separated by commas"
244	              value={formData?.hosts}
245	              onChange={event => handleInputChange('hosts', event.target.value)}
246	              isRequired
247	              id="source-hosts"
248	              name="hosts"
249	              data-ouia-component-id="hosts_multiple"
250	            />
251	            <HelperText>
252	              Type IP addresses, IP ranges, and DNS host names. Wildcards are valid. Use CIDR or Ansible notation for
253	              ranges.
254	            </HelperText>
255	          </FormGroup>
256	          <FormGroup label="Port" fieldId="port">
257	            <TextInput
258	              value={formData?.port}
259	              placeholder="Optional"
260	              type="text"
261	              id="source-port"
262	              name="port"
263	              onChange={event => handleInputChange('port', (event.target as HTMLInputElement).value)}
264	              ouiaId="port"
265	            />
266	            <HelperText>Default port is 22</HelperText>
267	          </FormGroup>
268	        </React.Fragment>
269	      ) : (
270	        <React.Fragment>
271	          <FormGroup label="IP address or hostname" isRequired fieldId="hosts">
272	            <TextInput
273	              value={formData?.hosts}
274	              onChange={event => handleInputChange('hosts', (event.target as HTMLInputElement).value)}
275	              isRequired
276	              id="source-hosts"
277	              data-testid="input-host"
278	              name="hosts"
279	              ouiaId="hosts_single"
280	            />
281	            <HelperText>Enter an IP address or hostname</HelperText>
282	          </FormGroup>
283	          <FormGroup label="Port" fieldId="port">
284	            <TextInput
285	              value={formData?.port}
286	              placeholder="Optional"
287	              type="text"
288	              id="source-port"
289	              data-testid="input-port"
290	              name="port"
291	              onChange={event => handleInputChange('port', (event.target as HTMLInputElement).value)}
292	              ouiaId="port"
293	            />
294	            <HelperText>Default port is {isOpenshift ? '6443' : '443'}</HelperText>
295	          </FormGroup>
296	          <FormGroup label="Proxy URL" fieldId="proxy_url">
297	            <TextInput
298	              value={formData?.proxy_url || ''}
299	              placeholder="Optional"
300	              type="text"
301	              id="proxy-url"
302	              data-testid="input-proxy"
303	              name="proxy_url"
304	              onChange={event => handleInputChange('proxy_url', (event.target as HTMLInputElement).value || undefined)}
305	              ouiaId="proxy_url"
306	            />
307	            <HelperText>Specify a proxy in the format protocol://host:port (if required).</HelperText>
308	          </FormGroup>
309	        </React.Fragment>
310	      )}
311	      {isNetwork ? (
312	        <FormGroup label="" fieldId="paramiko">
313	          <Checkbox
314	            key="paramiko"
315	            label="Connect using Paramiko instead of Open SSH"
316	            id="paramiko"
317	            isChecked={formData?.useParamiko}
318	            onChange={(_ev, checked) => handleInputChange('useParamiko', checked)}
319	            ouiaId="options_paramiko"
320	          />
321	        </FormGroup>
322	      ) : (
323	        <React.Fragment>
324	          <FormGroup label="Connection" fieldId="connection">
325	            <SimpleDropdown
326	              isFullWidth
327	              label={formData?.sslProtocol || 'Select protocol'}
328	              menuToggleOuiaId="options_ssl_protocol"
329	              variant={'default'}
330	              onSelect={item => handleInputChange('sslProtocol', item)}
331	              dropdownItems={[
332	                { item: 'SSLv23', ouiaId: 'sslv23' },
333	                { item: 'TLSv1', ouiaId: 'tlsv1' },
334	                { item: 'TLSv1.1', ouiaId: 'tlsv11' },
335	                { item: 'TLSv1.2', ouiaId: 'tlsv12' },
336	                { item: 'Disable SSL', ouiaId: 'disable_ssl' }
337	              ]}
338	            />
339	          </FormGroup>
340	          <FormGroup label="" fieldId="ssl_verify">
341	            <Checkbox
342	              key="ssl_verify"
343	              label="Verify SSL certificate"
344	              id="ssl_verify"
345	              isDisabled={formData?.sslProtocol === 'Disable SSL'}
346	              isChecked={formData?.sslProtocol !== 'Disable SSL' && formData?.sslVerify}
347	              onChange={(_ev, checked) => handleInputChange('sslVerify', checked)}
348	              ouiaId="options_ssl_cert"
349	            />
350	          </FormGroup>
351	        </React.Fragment>
352	      )}
353	      <ActionGroup>
354	        <Button variant="primary" onClick={onAdd}>
355	          Save
356	        </Button>
357	        <Button variant="link" onClick={() => onClose()}>
358	          Cancel
359	        </Button>
360	      </ActionGroup>
361	    </Form>
362	  );
363	};
364	
365	const AddSourceModal: React.FC<AddSourceModalProps> = ({
366	  isOpen,
367	  source,
368	  sourceType,
369	  onClose = () => {},
370	  onSubmit = () => {}
371	}) => (
372	  <Modal
373	    variant={ModalVariant.small}
374	    title={(source && `Edit Source: ${source.name || ''}`) || `Add Source: ${sourceType || ''}`}
375	    isOpen={isOpen}
376	    onClose={() => onClose()}
377	  >
378	    <SourceForm source={source} sourceType={sourceType} onClose={onClose} onSubmit={onSubmit} />
379	  </Modal>
380	);
381	
382	export { AddSourceModal as default, AddSourceModal, SourceForm, useSourceForm, type AddSourceModalProps };

